#include <bits/stdc++.h>
#include <queue>
using namespace std;
queue <int> Q;
int main() 
{
    int n=0;
    cin>>n;
    while(n!=0)
    {
        cout<<"Discarded cards: ";
        for(int i=1;i<=n;i++)
        {
            Q.push(i);
        }
        for(int i=1;i<=n-1;i++)
        {
            if(Q.size()==2)
            {
                cout<<Q.front()<<endl;
            }
            else
            {
                cout<<Q.front()<<", ";
            }
            Q.pop();
            Q.push(Q.front());
            Q.pop();
        }
        cout<<"Remaining card: "<<Q.front()<<endl;
        Q.pop();
        cin>>n;
    }
    return 0;
}
